      "metacarpals_phalanges_hand": "Metacarpals na Phalanges (Ukuboko)",
      "scaphoid_bone": "Igufwa rya Scaphoid",
      "600_muscles_movement_posture_heat_prod": "Imitsi 600+ — kwimuka, uko umuntu ahagaze, gukora ubushyuhe, guhamya ingingo.",
      "rotator_cuff_sits": "Rotator Cuff (SITS)",
      "iliopsoas": "Iliopsoas",
