      "points_c_where_iterating_z_z_c_stays_b": "Utudomo c aho gusubiramo z = z² + c bikomeza kuba mu mbibi. Amakuru adashira ku iyaguriro iryo ari ryo ryose. Ryavumbuwe 1980.",
      "julia_set": "Itsinda rya Julia",
      "for_each_c_points_z_where_iterating_z_": "Kuri buri c, utudomo z aho gusubiramo z = z² + c bikomeza kuba mu mbibi. Buri c gitanga itsinda rya Julia ritandukanye; hamwe bivuna itsinda rya Mandelbrot.",
      "dragon_curve": "Umuverure w'ikiyoka",
      "fold_a_strip_of_paper_in_half_repeated": "Kunja igice cy'urupapuro kabiri kenshi; ufungure buri kunja kuri 90°. Cyangwa gusimbura gusubiramo kw'imirongo.",
      "barnsley_fern": "Iyanana rya Barnsley",
