      "hausdorff_dimension": "Ingano ya Hausdorff",
      "fractional_dimension_coastline_1_2_1_3": "Ingano y'igice. Inkombe y'inyanja ~1.2-1.3 bitewe n'igihugu. Bifata \"ubukarabari\" hakurya y'ingano yuzuye.",
      "defining_property_strict_self_similari": "Ikiranga gisobanura. Kwisa-nyawe (Koch) cyangwa mu buryo bw'imibare (inkombe).",
      "real_world_fractals": "Furakitali z'isi nyayo",
      "coastlines_trees_lungs_bronchi_blood_v": "Inkombe z'inyanja, ibiti, ibihaha (bronches), imitsi y'amaraso, imiyoboro y'inzuzi, imisozi, ibicu, inkuba.",
      "flat_plane_parallel_postulate_holds_an": "Urwego rusanzuye. Igitekerezo-shingiro cy'imirongo iteganye kirakora. Inguni z'umutatu ziteranya neza kuri 180°.",
      "surface_of_sphere_triangle_angles_sum_": "Ubuso bw'umupira. Inguni z'umutatu ziteranya KURENZA 180°. Ikirenga gihuye n'ubuso. Bikoreshwa mu buyobozi bw'amato.",
      "saddle_shaped_surface_triangle_angles_": "Ubuso bufite imiterere y'intebe-farashi. Inguni z'umutatu ziteranya MUNSI ya 180°. Imirongo iteganye myinshi inyura ku kadomo katari ku murongo.",
      "shortest_paths_on_a_surface_straight_l": "Inzira ngufi ku buso. Imirongo igororotse (Euclide); inziga nini (umupira); imirongo ya hiperubolike.",
      "largest_circles_on_a_sphere_equator_me": "Inziga nini kurusha izindi ku mupira. Ekwateri + meridiyani. Indege zikurikira inzira z'uruziga runini.",
      "euclidean_0_spherical_positive_hyperbo": "Euclide = 0. Umupira = positifu. Hiperubolike = negatifu. Ukugoramye kugena geometiri.",
      "on_sphere_of_radius_r_triangle_area_r_": "Ku mupira w'umurambararo R, ubuso bw'umutatu = R² × (igiteranyo cy'inguni − π).",
      "positions_on_earth_s_surface_use_spher": "Ahantu ku buso bw'Isi hakoresha geometiri y'umupira (cyangwa mu buryo bwuzuye, ellipsoïdale).",
      "nyc_to_tokyo_is_shortest_via_the_arcti": "NYC kugeza Tokyo ni ngufi binyuze mu Arctique, atari mu buseruko bugororotse — iyo ni uruziga runini.",
      "spacetime_is_curved_by_mass_energy_geo": "Umwanya-gihe ugoramywa na misa-ngufi. Ba-géodésique inyura mu mwanya-gihe ugoramye NI zo nzira z'ibintu bigwa mu bwisanzure.",
