      "a_vertical_or_angled_gnomon_casts_a_sh": "\"Gnomon\" ihagaze cyangwa ifite inguni itera igicucu. Uko Isi izunguruka, igicucu kigenda ku bimenyetso.",
      "for_accuracy_gnomon_must_be_parallel_t": "Kubera ukuri, gnomon igomba kuba iteganye n'urumurongo-rwibumba rw'Isi — inguni ku butambike = latitude y'aho.",
      "dial_plate_perpendicular_to_gnomon_par": "Urubaho rw'isaha ruringaniye na gnomon (ruteganye n'ekwateri). Imirongo y'amasaha itandukanye kimwe na 15°.",
      "dial_plate_parallel_to_ground_hour_lin": "Urubaho rw'isaha ruteganye n'ubutaka. Imirongo y'amasaha ntitandukanye kimwe — uburyo: tan(inguni y'umurongo w'isaha) = sin(latitude) × tan(inguni y'isaha).",
      "dial_on_a_wall_hour_lines_depend_on_wa": "Isaha ku rukuta. Imirongo y'amasaha iterwa n'azimut y'urukuta + latitude.",
      "sundial_time_differs_from_clock_time_b": "Igihe cy'isaha y'izuba gitandukanye n'igihe cy'isaha kugeza ~16 iminota mu mwaka wose. Bitewe n'inzira ya ellipsoïdale y'Isi + kubera k'urumurongo-rwibumba.",
      "figure_8_trace_of_sun_s_position_at_sa": "Umurongo w'ishusho ya 8 y'aho izuba riri ku isaha imwe buri munsi mu mwaka. Byerekanwa ku masaha y'izuba amwe agezweho.",
      "sundial_shows_local_apparent_solar_tim": "Isaha y'izuba yerekana IGIHE CY'IZUBA cy'aho kigaragara. Gitandukanye n'igihe cya gisivili ku itandukaniro rya longitude mu karere k'igihe + DST.",
      "very_precise_sundials_with_corrections": "Amasaha y'izuba anonosoye afite ivugurura ry'uburinganire bw'igihe + longitude. Anyaburinganire kugeza kuri segonda.",
      "phi_1_61803398874989_irrational_roots_": "φ (phi) ≈ 1.61803398874989... Idasobanutse. Imizi ya x² = x + 1.",
      "algebraic_definition": "Ibisobanuro bya algebra",
      "a_line_divided_so_that_whole_larger_la": "Umurongo ugabanyijwe ku buryo cyose : kinini = kinini : gito. (a+b)/a = a/b = φ.",
      "fibonacci_connection": "Isano rya Fibonacci",
      "ratio_of_consecutive_fibonacci_numbers": "Igipimo cy'imibare ya Fibonacci ikurikirana kegera φ: 1, 1, 2, 3, 5, 8, 13, 21 → 21/13 ≈ 1.615.",
      "golden_rectangle": "Kare-refu ya zahabu",
