      "in_nature": "Mu kamere",
      "spiral_arrangements_in_sunflowers_pine": "Iboneza ry'umuzingo mu ndabyo z'izuba, ibibabi bya pine, amagi ya nautilus. Byerekana gupakira kwiza ku meristème akura.",
      "in_art_overstated": "Mu bugeni (byavuzwe birenze)",
      "often_claimed_in_parthenon_mona_lisa_e": "Kenshi bivugwa muri Parthénon, Mona Lisa, n'ibindi — ibivugwa byinshi ntibishyigikiwe. Ubugeni nyabwo bw'igipimo cya zahabu: gukoresha kubishaka mu kinyejana cya 20 (Le Corbusier, Dali).",
      "aesthetic_claim": "Ivuga ry'\"ubwiza\"",
      "long_believed_humans_find_golden_ratio": "Igihe kirekire bemeraga ko abantu babona igipimo cya zahabu ari cyo cyiza kurusha ibindi. Ibimenyetso bikomeye ni bike kuruta uko inkuru zizwi zivuga.",
      "continued_fraction": "Igice gikomeza",
      "1_1_1_1_1_1_most_irrational_number_slo": "φ = 1 + 1/(1 + 1/(1 + 1/(...))). Umubare udasobanutse kurusha iyindi — igice gikomeza kegereza buhoro kurusha ibindi.",
      "mathematical_origami": "Origami y'imibare",
      "active_research_area_can_solve_cubic_e": "Akarere k'ubushakashatsi gakora. Ashobora gukemura ingingano za kibe (bidashoboka na kompazi + umurongo ugororotse gusa). Bihuza na algebra.",
      "maekawa_s_theorem": "Igitekerezo cya Maekawa",
      "at_any_flat_foldable_vertex_mountain_f": "Kuri buri mpinga ishobora gukunjwa neza, |# amakunja y'umusozi − # amakunja y'ikibaya| = 2.",
      "kawasaki_s_theorem": "Igitekerezo cya Kawasaki",
      "at_a_flat_foldable_vertex_alternating_": "Kuri impinga ishobora gukunjwa neza, inguni zisimburana zikikije impinga ziteranya kuri 180°.",
      "7_fold_limit_paper": "Urugero rw'amakunja 7 (urupapuro)",
